@page "/category/{CategoryName}"
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<div class="category-header">
    <h1>@CategoryName Recipes</h1>
    <a href="/" class="back-link">← Back to Categories</a>
</div>

@if (recipes.Count == 0)
{
    <p class="empty-message">No recipes found in this category yet. <a href="/submit">Be the first to add one!</a></p>
}
else
{
    <div class="recipe-grid">
        @foreach (var recipe in recipes)
        {
            <a href="/recipe/@recipe.Id" class="recipe-card">
                <h3>@recipe.Title</h3>
                <p class="recipe-description">@recipe.Description</p>
                <div class="recipe-card-footer">
                    <span class="rating-display">
                        @for (int i = 1; i <= 5; i++)
                        {
                            <span class="star-display @(i <= Math.Round(recipe.AverageRating) ? "star-filled" : "star-empty")">
                                @(i <= Math.Round(recipe.AverageRating) ? "★" : "☆")
                            </span>
                        }
                        @if (recipe.TotalRatings > 0)
                        {
                            <span class="rating-count">(@recipe.TotalRatings)</span>
                        }
                    </span>
                </div>
            </a>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = "";

    private List<Recipe> recipes = new();

    protected override void OnInitialized()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

