            <span class="recipe-category-badge">@recipe.Category</span>
        </div>

        <p class="recipe-detail-description">@recipe.Description</p>

        <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" TotalRatings="recipe.TotalRatings" @rendermode="InteractiveServer" />

        <div class="recipe-sections">
