@page "/submit"
@rendermode InteractiveServer
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<div class="submit-page">
    <h1>Share Your Recipe</h1>
    <p class="submit-intro">Have a delicious recipe? Share it with the RecipeShare community!</p>

    @if (submitted)
    {
        <div class="success-message">
            <h2>🎉 Recipe Submitted!</h2>
            <p>Your recipe "<strong>@title</strong>" has been added successfully.</p>
            <a href="/recipe/@newRecipeId" class="hero-cta">View Your Recipe</a>
        </div>
    }
    else
    {
        <EditForm Model="@this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
            <DataAnnotationsValidator />

            <div class="form-group">
                <label for="title">Title *</label>
                <InputText id="title" @bind-Value="title" class="form-control" required />
            </div>

            <div class="form-group">
                <label for="category">Category *</label>
                <InputSelect id="category" @bind-Value="category" class="form-control" required>
                    <option value="">-- Select a category --</option>
                    <option value="Breakfast">Breakfast</option>
                    <option value="Lunch">Lunch</option>
                    <option value="Dinner">Dinner</option>
                    <option value="Desserts">Desserts</option>
                </InputSelect>
            </div>

            <div class="form-group">
                <label for="description">Description</label>
                <InputTextArea id="description" @bind-Value="description" class="form-control" rows="3" />
            </div>

            <div class="form-group">
                <label for="ingredients">Ingredients (one per line)</label>
                <InputTextArea id="ingredients" @bind-Value="ingredientsText" class="form-control" rows="5" placeholder="1 cup flour&#10;2 eggs&#10;1 tsp vanilla" />
            </div>

            <div class="form-group">
                <label for="steps">Steps (one per line)</label>
                <InputTextArea id="steps" @bind-Value="stepsText" class="form-control" rows="5" placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
            </div>

            <button type="submit" class="btn-submit" disabled="@(string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(category))">
                Submit Recipe
            </button>
        </EditForm>
    }
</div>

@code {
    private string title = "";
    private string category = "";
    private string description = "";
    private string ingredientsText = "";
    private string stepsText = "";
    private bool submitted = false;
    private int newRecipeId = 0;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(category))
            return;

        var recipe = new Recipe
        {
            Title = title,
            Category = category,
            Description = description,
            Ingredients = ingredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries)
                .Select(i => i.Trim())
                .Where(i => !string.IsNullOrWhiteSpace(i))
                .ToList(),
            Steps = stepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries)
                .Select(s => s.Trim())
                .Where(s => !string.IsNullOrWhiteSpace(s))
                .ToList()
        };

        var added = RecipeService.Add(recipe);
        newRecipeId = added.Id;
        submitted = true;
    }
}

@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="star-rating">
    <span class="star-rating-label">Rate this recipe:</span>
    <div class="stars-container">
        @for (int i = 1; i <= 5; i++)
        {
            var starValue = i;
            <span class="star-interactive @(starValue <= displayRating ? "star-filled" : "star-empty")"
                  @onclick="() => Rate(starValue)"
                  @onmouseover="() => hoverRating = starValue"
                  @onmouseout="() => hoverRating = 0">
                @(starValue <= displayRating ? "★" : "☆")
            </span>
        }
    </div>
    <span class="rating-info">
        @if (hasRated)
        {
            <span class="rated-message">Thanks for rating!</span>
        }
        @currentRating.ToString("0.0") / 5
        (@totalRatings @(totalRatings == 1 ? "rating" : "ratings"))
    </span>
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    [Parameter]
    public double CurrentRating { get; set; }

    [Parameter]
    public int TotalRatings { get; set; }

    private double currentRating;
    private int totalRatings;
    private int hoverRating = 0;
    private bool hasRated = false;

    private int displayRating => hoverRating > 0 ? hoverRating : (int)Math.Round(currentRating);

    protected override void OnParametersSet()
    {
        currentRating = CurrentRating;
        totalRatings = TotalRatings;
    }

    private void Rate(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe != null)
        {
            currentRating = recipe.AverageRating;
            totalRatings = recipe.TotalRatings;
        }
        hasRated = true;
    }
}

