    <div class="stars-container">
        @for (int i = 1; i <= 5; i++)
        {
            var starValue = i;
            <span class="star-interactive @(starValue <= displayRating ? "star-filled" : "star-empty")"
                  @onclick="() => Rate(starValue)"
                  @onmouseover="() => hoverRating = starValue"
                  @onmouseout="() => hoverRating = 0">
                @(starValue <= displayRating ? "★" : "☆")
            </span>
        }
    </div>
    <span class="rating-info">
        @if (hasRated)
        {
            <span class="rated-message">Thanks for rating!</span>
        }
        @currentRating.ToString("0.0") / 5
        (@totalRatings @(totalRatings == 1 ? "rating" : "ratings"))
    </span>
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    [Parameter]
    public double CurrentRating { get; set; }

    [Parameter]
    public int TotalRatings { get; set; }

    private double currentRating;
    private int totalRatings;
    private int hoverRating = 0;
    private bool hasRated = false;

    private int displayRating => hoverRating > 0 ? hoverRating : (int)Math.Round(currentRating);

    protected override void OnParametersSet()
    {
        currentRating = CurrentRating;
        totalRatings = TotalRatings;
    }

    private void Rate(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe != null)
        {
            currentRating = recipe.AverageRating;
            totalRatings = recipe.TotalRatings;
        }
        hasRated = true;
    }
}

